import unittest
from parser import parse_scores

class TestParser(unittest.TestCase):
    def test_basic_parse(self):
        csv = 'name,score\nAlice,90\nBob,85'
        result = parse_scores(csv)
        self.assertEqual(result, {'Alice': 90, 'Bob': 85})
    def test_invalid_score(self):
        csv = 'name,score\nAlice,90\nBob,invalid'
        result = parse_scores(csv)
        self.assertEqual(result, {'Alice': 90})

if __name__ == '__main__':
    unittest.main()
